operations.reducer:
state.title = action.input.title;
state.description = action.input.description;
state.content = action.input.content || null;
state.involvedRefs = action.input.involvedRefs;
state.status = "OPEN";
state.observedAt = action.input.observedAt;
state.observedBy = action.input.observedBy || null;

operations.schema:
input ResolveTensionInput {
    resolution: String!
    resolvedAt: DateTime!
}

operations.reducer:
if (state.status !== "OPEN") throw new TensionAlreadyResolvedError("Tension is not open");
state.status = "RESOLVED";
state.resolution = action.input.resolution;
state.resolvedAt = action.input.resolvedAt;

operations.schema:
input DissolveTensionInput {
    resolution: String!
    resolvedAt: DateTime!
}

operations.reducer:
if (state.status !== "OPEN") throw new TensionAlreadyResolvedError("Tension is not open");
state.status = "DISSOLVED";
state.resolution = action.input.resolution;
state.resolvedAt = action.input.resolvedAt;
